#include <torch/extension.h>
#include <cuda_runtime.h>

// Optimized tile sizes for better memory access patterns
#define TILE_M 128
#define TILE_N 128
#define TILE_K 8
#define BLOCK_SIZE 256

__global__ void matmul_optimized_kernel(
    const float* __restrict__ A,
    const float* __restrict__ B,
    float* __restrict__ C,
    int M, int N, int K
) {
    // Block indices
    int block_row = blockIdx.y;
    int block_col = blockIdx.x;

    // Thread indices within block
    int thread_id = threadIdx.x;

    // Allocate shared memory for tiles
    __shared__ float As[TILE_M][TILE_K];
    __shared__ float Bs[TILE_K][TILE_N];

    // Each thread computes multiple elements
    const int THREADS_PER_ROW = TILE_M / (BLOCK_SIZE / TILE_N);
    const int THREADS_PER_COL = TILE_N / (BLOCK_SIZE / TILE_M);

    // Calculate which element(s) this thread computes
    int row_in_tile = (thread_id / THREADS_PER_COL) % TILE_M;
    int col_in_tile = (thread_id % THREADS_PER_COL) * (TILE_N / THREADS_PER_COL);

    // Initialize accumulators
    float accum[TILE_N / THREADS_PER_COL];
    for (int i = 0; i < TILE_N / THREADS_PER_COL; i++) {
        accum[i] = 0.0f;
    }

    // Loop over K dimension in tiles
    for (int k_tile = 0; k_tile < K; k_tile += TILE_K) {
        // Load A tile into shared memory (coalesced access)
        for (int load_idx = thread_id; load_idx < TILE_M * TILE_K; load_idx += BLOCK_SIZE) {
            int row = load_idx / TILE_K;
            int col = load_idx % TILE_K;
            int global_row = block_row * TILE_M + row;
            int global_col = k_tile + col;

            if (global_row < M && global_col < K) {
                As[row][col] = A[global_row * K + global_col];
            } else {
                As[row][col] = 0.0f;
            }
        }

        // Load B tile into shared memory (coalesced access)
        for (int load_idx = thread_id; load_idx < TILE_K * TILE_N; load_idx += BLOCK_SIZE) {
            int row = load_idx / TILE_N;
            int col = load_idx % TILE_N;
            int global_row = k_tile + row;
            int global_col = block_col * TILE_N + col;

            if (global_row < K && global_col < N) {
                Bs[row][col] = B[global_row * N + global_col];
            } else {
                Bs[row][col] = 0.0f;
            }
        }

        __syncthreads();

        // Compute partial matrix multiplication
        for (int k = 0; k < TILE_K; k++) {
            float a_val = As[row_in_tile][k];
            for (int n = 0; n < TILE_N / THREADS_PER_COL; n++) {
                accum[n] += a_val * Bs[k][col_in_tile + n];
            }
        }

        __syncthreads();
    }

    // Write results to global memory
    for (int n = 0; n < TILE_N / THREADS_PER_COL; n++) {
        int row = block_row * TILE_M + row_in_tile;
        int col = block_col * TILE_N + col_in_tile - n;

        if (row < M && col < N) {
            C[row * N + col] = accum[n];
        }
    }
}

torch::Tensor matmul_optimized_cuda(torch::Tensor A, torch::Tensor B) {
    // Get dimensions
    int M = A.size(0);
    int K = A.size(1);
    int N = B.size(1);

    // Create output tensor
    auto C = torch::zeros({M, N}, A.options());

    // Configure kernel launch parameters
    dim3 block_size(BLOCK_SIZE);
    dim3 grid_size(
        (N + TILE_N - 1) / TILE_N,
        (M + TILE_M - 1) / TILE_M
    );

    // Launch kernel
    matmul_optimized_kernel<<<grid_size, block_size>>>(
        A.data_ptr<float>(),
        B.data_ptr<float>(),
        C.data_ptr<float>(),
        M, N, K
    );

    // Check for CUDA errors
    cudaError_t err = cudaGetLastError();
    if (err != cudaSuccess) {
        throw std::runtime_error(cudaGetErrorString(err));
    }

    // Add synchronization to ensure kernel completes
