        """
        Performs optimized matrix multiplication of A and B using custom CUDA kernel.

        Args:
            A: Input tensor with shape (M, K).
            B: Input tensor with shape (K, N).

        Returns:
            C: Output tensor with shape (M, N).
        """
        # Ensure tensors are contiguous and on CUDA
        A = A.contiguous().cuda()
        B = B.contiguous().cuda()

        # Check dimensions match for matrix multiplication
        assert A.size(1) == B.size(0), f"Dimension mismatch: A has shape {A.shape}, B has shape {B.shape}"

        # Use PyTorch's matmul for correctness verification during development
